PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE Veicolo (
    idVeicolo INTEGER PRIMARY KEY AUTOINCREMENT,
    marca TEXT NOT NULL,
    modello TEXT NOT NULL,
    colore TEXT NOT NULL,
    prezzo_giornaliero REAL NOT NULL CHECK (prezzo_giornaliero >= 0),
    stato TEXT NOT NULL DEFAULT 'disponibile' CHECK (stato IN ('disponibile', 'noleggiato', 'manutenzione', 'non_disponibile')),
    tipo TEXT NOT NULL CHECK (tipo IN ('auto', 'scooter', 'barca', 'bici elettrica'))
, cambio TEXT CHECK (cambio IN ('manuale', 'automatica')), cabrio INTEGER NOT NULL DEFAULT 0 CHECK (cabrio IN (0, 1)), targa TEXT, cilindrata INTEGER CHECK (cilindrata IN (50, 125, 200)), batteria_watt INTEGER CHECK (batteria_watt IN (250, 500)), lunghezza REAL CHECK (lunghezza IS NULL OR lunghezza > 0));
CREATE TABLE IF NOT EXISTS "django_migrations" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app" varchar(255) NOT NULL, "name" varchar(255) NOT NULL, "applied" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "django_content_type" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app_label" varchar(100) NOT NULL, "model" varchar(100) NOT NULL);
CREATE TABLE IF NOT EXISTS "auth_group_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "auth_user_groups" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "auth_user_user_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "auth_permission" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "content_type_id" integer NOT NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "codename" varchar(100) NOT NULL, "name" varchar(255) NOT NULL);
CREATE TABLE IF NOT EXISTS "auth_group" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(150) NOT NULL UNIQUE);
CREATE TABLE IF NOT EXISTS "auth_user" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "password" varchar(128) NOT NULL, "last_login" datetime NULL, "is_superuser" bool NOT NULL, "username" varchar(150) NOT NULL UNIQUE, "last_name" varchar(150) NOT NULL, "email" varchar(254) NOT NULL, "is_staff" bool NOT NULL, "is_active" bool NOT NULL, "date_joined" datetime NOT NULL, "first_name" varchar(150) NOT NULL);
CREATE TABLE IF NOT EXISTS "django_session" ("session_key" varchar(40) NOT NULL PRIMARY KEY, "session_data" text NOT NULL, "expire_date" datetime NOT NULL);
CREATE TABLE Utente (idUtente INTEGER PRIMARY KEY AUTOINCREMENT, nome TEXT NOT NULL, cognome TEXT, mail TEXT UNIQUE, telefono TEXT, password_hash TEXT, tipo TEXT NOT NULL CHECK (tipo IN ('cliente', 'admin', 'staff')));
CREATE TABLE Staff (idStaff INTEGER PRIMARY KEY AUTOINCREMENT, idUtente INTEGER NOT NULL UNIQUE, ruolo TEXT NOT NULL, stipendio REAL NOT NULL DEFAULT 0, FOREIGN KEY (idUtente) REFERENCES Utente(idUtente) ON UPDATE CASCADE ON DELETE RESTRICT);
CREATE TABLE Prenotazione (idPrenotazione INTEGER PRIMARY KEY AUTOINCREMENT, idUtente INTEGER NOT NULL, idVeicolo INTEGER NOT NULL, tipo_ritiro TEXT NOT NULL, indirizzo_ritiro TEXT NOT NULL, data_inizio TEXT NOT NULL, data_fine TEXT NOT NULL, stato TEXT NOT NULL DEFAULT 'in_attesa' CHECK (stato IN ('in_attesa', 'accettata', 'rifiutata', 'in_corso', 'completata')), costo_previsto REAL NOT NULL DEFAULT 0 CHECK (costo_previsto >= 0), cauzione_richiesta REAL NOT NULL DEFAULT 0 CHECK (cauzione_richiesta >= 0), note TEXT, CHECK (date(data_inizio) IS NOT NULL), CHECK (date(data_fine) IS NOT NULL), CHECK (date(data_inizio) < date(data_fine)), FOREIGN KEY (idUtente) REFERENCES Utente(idUtente) ON UPDATE CASCADE ON DELETE RESTRICT, FOREIGN KEY (idVeicolo) REFERENCES Veicolo(idVeicolo) ON UPDATE CASCADE ON DELETE RESTRICT);
CREATE TABLE Contratto (idContratto INTEGER PRIMARY KEY AUTOINCREMENT, idPrenotazione INTEGER NOT NULL UNIQUE, idVeicolo INTEGER NOT NULL, idStaff INTEGER, data_stipula TEXT, costo_totale REAL NOT NULL CHECK (costo_totale >= 0), cauzione_importo REAL NOT NULL DEFAULT 0 CHECK (cauzione_importo >= 0), cauzione_stato TEXT NOT NULL DEFAULT 'richiesto' CHECK (cauzione_stato IN ('richiesto', 'pagato', 'rimborsato')), cauzione_data_pagamento TEXT, saldo_importo REAL NOT NULL DEFAULT 0 CHECK (saldo_importo >= 0), saldo_stato TEXT NOT NULL DEFAULT 'richiesto' CHECK (saldo_stato IN ('richiesto', 'pagato', 'rimborsato')), saldo_data_pagamento TEXT, CHECK (data_stipula IS NULL OR date(data_stipula) IS NOT NULL), FOREIGN KEY (idPrenotazione) REFERENCES Prenotazione(idPrenotazione) ON UPDATE CASCADE ON DELETE RESTRICT, FOREIGN KEY (idVeicolo) REFERENCES Veicolo(idVeicolo) ON UPDATE CASCADE ON DELETE RESTRICT, FOREIGN KEY (idStaff) REFERENCES Staff(idStaff) ON UPDATE CASCADE ON DELETE RESTRICT);
DELETE FROM sqlite_sequence;
CREATE UNIQUE INDEX idx_veicolo_demo_unique ON Veicolo(marca, modello, colore, tipo);
CREATE UNIQUE INDEX idx_veicolo_targa ON Veicolo(targa);
CREATE UNIQUE INDEX "django_content_type_app_label_model_76bd3d3b_uniq" ON "django_content_type" ("app_label", "model");
CREATE UNIQUE INDEX "auth_group_permissions_group_id_permission_id_0cd325b0_uniq" ON "auth_group_permissions" ("group_id", "permission_id");
CREATE INDEX "auth_group_permissions_group_id_b120cbf9" ON "auth_group_permissions" ("group_id");
CREATE INDEX "auth_group_permissions_permission_id_84c5c92e" ON "auth_group_permissions" ("permission_id");
CREATE UNIQUE INDEX "auth_user_groups_user_id_group_id_94350c0c_uniq" ON "auth_user_groups" ("user_id", "group_id");
CREATE INDEX "auth_user_groups_user_id_6a12ed8b" ON "auth_user_groups" ("user_id");
CREATE INDEX "auth_user_groups_group_id_97559544" ON "auth_user_groups" ("group_id");
CREATE UNIQUE INDEX "auth_user_user_permissions_user_id_permission_id_14a6b632_uniq" ON "auth_user_user_permissions" ("user_id", "permission_id");
CREATE INDEX "auth_user_user_permissions_user_id_a95ead1b" ON "auth_user_user_permissions" ("user_id");
CREATE INDEX "auth_user_user_permissions_permission_id_1fbb5f2c" ON "auth_user_user_permissions" ("permission_id");
CREATE UNIQUE INDEX "auth_permission_content_type_id_codename_01ab375a_uniq" ON "auth_permission" ("content_type_id", "codename");
CREATE INDEX "auth_permission_content_type_id_2f476e4b" ON "auth_permission" ("content_type_id");
CREATE INDEX "django_session_expire_date_a5c62663" ON "django_session" ("expire_date");
CREATE INDEX idx_prenotazione_utente ON Prenotazione(idUtente);
CREATE INDEX idx_prenotazione_veicolo_periodo ON Prenotazione(idVeicolo, data_inizio, data_fine);
CREATE INDEX idx_contratto_veicolo ON Contratto(idVeicolo);
CREATE INDEX idx_contratto_staff ON Contratto(idStaff);
CREATE TRIGGER trg_prenotazione_no_overlap_insert BEFORE INSERT ON Prenotazione FOR EACH ROW WHEN NEW.stato NOT IN ('rifiutata') BEGIN SELECT RAISE(ABORT, 'Il veicolo e gia prenotato in un periodo sovrapposto') WHERE EXISTS (SELECT 1 FROM Prenotazione p WHERE p.idVeicolo = NEW.idVeicolo AND p.stato NOT IN ('rifiutata') AND date(NEW.data_inizio) < date(p.data_fine) AND date(NEW.data_fine) > date(p.data_inizio)); END;
CREATE TRIGGER trg_prenotazione_no_overlap_update BEFORE UPDATE OF idVeicolo, data_inizio, data_fine, stato ON Prenotazione FOR EACH ROW WHEN NEW.stato NOT IN ('rifiutata') BEGIN SELECT RAISE(ABORT, 'Il veicolo e gia prenotato in un periodo sovrapposto') WHERE EXISTS (SELECT 1 FROM Prenotazione p WHERE p.idPrenotazione <> NEW.idPrenotazione AND p.idVeicolo = NEW.idVeicolo AND p.stato NOT IN ('rifiutata') AND date(NEW.data_inizio) < date(p.data_fine) AND date(NEW.data_fine) > date(p.data_inizio)); END;
CREATE TRIGGER trg_contratto_veicolo_coerente_insert BEFORE INSERT ON Contratto FOR EACH ROW BEGIN SELECT RAISE(ABORT, 'Il veicolo del contratto deve coincidere con quello della prenotazione') WHERE NOT EXISTS (SELECT 1 FROM Prenotazione p WHERE p.idPrenotazione = NEW.idPrenotazione AND p.idVeicolo = NEW.idVeicolo AND p.stato <> 'rifiutata'); END;
CREATE TRIGGER trg_contratto_veicolo_coerente_update BEFORE UPDATE OF idPrenotazione, idVeicolo ON Contratto FOR EACH ROW BEGIN SELECT RAISE(ABORT, 'Il veicolo del contratto deve coincidere con quello della prenotazione') WHERE NOT EXISTS (SELECT 1 FROM Prenotazione p WHERE p.idPrenotazione = NEW.idPrenotazione AND p.idVeicolo = NEW.idVeicolo AND p.stato <> 'rifiutata'); END;
COMMIT;
